import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.CQMe4Urg.js";const m=JSON.parse('{"title":"第七章 RAG 检索增强生成 -- 让 LLM 拥有你的知识库","description":"","frontmatter":{},"headers":[],"relativePath":"07-rag/index.md","filePath":"07-rag/index.md","lastUpdated":1776333512000}'),i={name:"07-rag/index.md"};function n(l,t,o,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="第七章-rag-检索增强生成-让-llm-拥有你的知识库" tabindex="-1">第七章 RAG 检索增强生成 -- 让 LLM 拥有你的知识库 <a class="header-anchor" href="#第七章-rag-检索增强生成-让-llm-拥有你的知识库" aria-label="Permalink to &quot;第七章 RAG 检索增强生成 -- 让 LLM 拥有你的知识库&quot;">​</a></h1><p>LLM 很聪明，但它只知道训练数据里的东西。你公司的内部文档、最新的产品手册、昨天刚发布的技术规范 -- 这些它统统不知道。更麻烦的是，它还可能自信满满地&quot;编造&quot;答案（幻觉问题）。</p><p><strong>RAG（Retrieval-Augmented Generation）就是解决这个问题的核武器。</strong> 核心思路很简单：用户提问时，先从你的知识库里搜出相关内容，然后把这些内容连同问题一起交给 LLM，让它&quot;带着参考资料&quot;回答。就像开卷考试一样，有了参考材料，LLM 的回答既准确又有据可查。</p><p>这一章从最基础的向量检索讲起，经过分块策略、混合检索、重排序等优化手段，最后到 Agentic RAG 和 Self-RAG 等前沿架构。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><ul><li><a href="./beginner.html">入门篇</a> -- 为什么需要 RAG、Embedding 原理、ChromaDB 入门、搭建完整的 RAG 管道</li><li><a href="./intermediate.html">进阶篇</a> -- 分块策略、混合检索、Reranking、查询改写、元数据过滤</li><li><a href="./advanced.html">高级篇</a> -- Agentic RAG、Graph RAG、Self-RAG、CRAG、RAG 评估框架</li></ul><h2 id="核心概念速览" tabindex="-1">核心概念速览 <a class="header-anchor" href="#核心概念速览" aria-label="Permalink to &quot;核心概念速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话解释</th></tr></thead><tbody><tr><td>RAG</td><td>检索增强生成，先搜索再回答的技术范式</td></tr><tr><td>Embedding</td><td>把文本转换成向量（一串数字），语义相近的文本向量也相近</td></tr><tr><td>向量数据库</td><td>专门存储和检索向量的数据库（ChromaDB、Pinecone 等）</td></tr><tr><td>分块（Chunking）</td><td>把长文档切成适合检索的小段落</td></tr><tr><td>混合检索</td><td>向量搜索 + 关键词搜索，取长补短</td></tr><tr><td>Reranking</td><td>对初步检索结果二次排序，提高相关性</td></tr><tr><td>Agentic RAG</td><td>Agent 自主决定是否检索、如何检索</td></tr><tr><td>Self-RAG</td><td>LLM 自我评估检索质量，决定是否需要重新检索</td></tr></tbody></table><h2 id="学完你能做到" tabindex="-1">学完你能做到 <a class="header-anchor" href="#学完你能做到" aria-label="Permalink to &quot;学完你能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>能力</th></tr></thead><tbody><tr><td>入门</td><td>理解 Embedding 原理、用 ChromaDB 构建知识库、搭建完整的文档问答系统</td></tr><tr><td>进阶</td><td>选择合适的分块策略、实现混合检索和重排序、用查询改写提升检索质量</td></tr><tr><td>高级</td><td>构建 Agent 自主驱动的 RAG 系统、实现检索质量自评估、设计 RAG 评估流水线</td></tr></tbody></table><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><ul><li>已完成前面章节，理解 LLM API 调用和 Tool Use</li><li>理解基础的线性代数概念（向量、点积 -- 不需要很深，有直觉就够）</li><li>有 Python 基础，会安装和使用第三方库</li></ul>',12)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
